// Clear stale SelectedMLVs only when mode transitions away from SelectedOnly.
// CurrentLakehouse mode legitimately uses SelectedMLVs for recursive ancestor
// traversal (CatalogHandler.cs:349), so blanket clearing would break that.

[TestMethod("ToInternalPatchRequest: Switching from Selected to All mode clears stale SelectedMLVs")]
...
result.ExecutionMode.Should().Be(ExecutionMode.CurrentLakehouse);
result.SelectedMLVs.Should().BeEmpty(
    "SelectedMLVs should be cleared when mode changes away from SelectedOnly to prevent stale filtering in CatalogHandler");

[TestMethod("ToInternalPatchRequest: Switching from Selected to FullLineage mode clears stale SelectedMLVs")]
...
result.ExecutionMode.Should().Be(ExecutionMode.FullLineage);
result.SelectedMLVs.Should().BeEmpty(
    "SelectedMLVs should be cleared when transitioning from SelectedOnly to FullLineage");

[TestMethod("ToInternalPatchRequest: CurrentLakehouse with existing SelectedMLVs preserves them on no-op PATCH")]
...
result.ExecutionMode.Should().Be(ExecutionMode.CurrentLakehouse);
result.SelectedMLVs.Should().BeEquivalentTo(
    new List<string> { "schema.mlv1", "schema.mlv2" },
    "CurrentLakehouse SelectedMLVs must be preserved — CatalogHandler uses them for recursive ancestor traversal");
